  });
}

startServer();

const SERVICE_MAP = {
    core: process.env.CORE_BACKEND_URL,
    item_master: process.env.ITEM_MASTER_BACKEND_URL,
    tracking: process.env.TRACKING_BACKEND_URL,
    data_sync: process.env.DATA_SYNC_BACKEND_URL,
  };

  module.exports = { SERVICE_MAP };
  /**
 * https://docs.cloud.google.com/run/docs/authenticating/service-to-service
 */
const { GoogleAuth } = require("google-auth-library");

const auth = new GoogleAuth();

function isLocalHttpBackend(url) {
  try {
    const u = new URL(url);
    return (
      u.protocol === "http:" &&
      (u.hostname === "localhost" || u.hostname === "127.0.0.1")
    );
  } catch {
    return false;
  }
}

/**
 * Cloud Run requires an OIDC identity token in Authorization.
 * The app JWT is forwarded in X-User-Authorization so backends can keep using req.headers.authorization.
 * Local HTTP backends skip OIDC; the browser's Authorization header is forwarded unchanged.
 */
async function attachInvokingIdentityHeaders(backendUrl, req) {
  if (isLocalHttpBackend(backendUrl)) {
    return;
  }
  const targetAudience = backendUrl.replace(/\/$/, "");
  const client = await auth.getIdTokenClient(targetAudience);
  const idToken = await client.idTokenProvider.fetchIdToken(targetAudience);
  const userAuth = req.headers.authorization;
  req.headers.authorization = `Bearer ${idToken}`;
  if (userAuth) {
    req.headers["x-user-authorization"] = userAuth;
  }
}

module.exports = { attachInvokingIdentityHeaders };
const express = require("express");
const httpProxy = require("http-proxy");
const { SERVICE_MAP } = require("../src/serviceMap");
const { attachInvokingIdentityHeaders } = require("../src/backendProxy");

const router = express.Router();

const proxy = httpProxy.createProxyServer({
  xfwd: true,
  proxyTimeout: 0,
  timeout: 0,
});

proxy.on("error", (err, req, res) => {
  console.error("[BFF proxy error]", err?.message || err);
  if (res && !res.headersSent && typeof res.writeHead === "function") {
    res.writeHead(502, { "Content-Type": "application/json" });
    res.end(JSON.stringify({ error: "Bad gateway" }));
  }
});

/**
 * /api/<service>/<backend-path>
 * Example: /api/core/getAllItems, /api/item_master/lib/getAllitems
 */
router.use(async (req, res) => {
  const pathname = req.path.replace(/^\//, "");
  const segments = pathname.split("/").filter(Boolean);
  const service = segments[0];
  const backendPath = segments.slice(1).join("/");

  const backendUrl = SERVICE_MAP[service];
  if (!backendUrl) {
    return res.status(404).json({
      error: `Unknown backend service: ${service}`,
    });
  }
  if (!backendPath) {
    return res.status(404).json({ error: "Missing backend path" });
  }

  const qIdx = req.url.indexOf("?");
  const search = qIdx !== -1 ? req.url.substring(qIdx) : "";

  try {
    await attachInvokingIdentityHeaders(backendUrl, req);
    req.url = `/${backendPath}${search}`;

    proxy.web(req, res, {
      target: backendUrl.replace(/\/$/, ""),
      changeOrigin: true,
    });
  } catch (err) {
    console.error(`[BFF ERROR] ${service} ${req.method} ${req.originalUrl}`, err.message);
    if (!res.headersSent) {
      res
        .status(err.response?.status || 500)
        .send(err.response?.data || { error: err.message || "Backend request failed" });
    }
  }
});

module.exports = router;

